sp_angular_provider.script:
/* Use this Directive to add icons for the suspense date and have a table cell with a hover popover function
//
// Copyrights belong to Discover Technologies LLC. © 2023 Discover Technologies LLC
// Special License Rights
//  The Government's rights to use, display, or disclose this software are restricted.
//  Any reproduction of computer software, computer software documentation,
//  or portions thereof marked with this legend must also reproduce the markings. 
// Script Continued Below
//
*/
function dtechActions(getTemplateUrl, spModal, spUtil, $timeout) {
	var dtechDirective = {
		restrict: 'E',
		// replace: true,
		// @: string 1 way, =: object 2 way, <: object 1 way,
		// &: execute an expression in the context of the parent scope, ?: the binding is optional
		scope: {
			dtechIsDark:"<",
			dtechInDataTable:"<?",
			dtechIsModal: "<",
			dtechPopoverPlacement: '@?',
			dtechTable: '@',
			dtechTaskSysId: '@',
			dtechToolTipOpen: "=?",
			dtechActionsObject: "=",
			loadActions: "=",
		},
		controller: directiveCtrl,
		link: link,
		controllerAs: 'd',
		templateUrl: getTemplateUrl('x_153465_discovert_dtechActions.html')
	};
	return dtechDirective;

	function directiveCtrl($scope, $rootScope, spModal, spUtil, $attrs, $animate, dtechTaskService, dtechTemplateService) {
		var d = this;
		var CONST_MAX_ACTION_WAIT_RETRY = 5;
		// have local per directive instead of global - TODO: get from a service
		// increase since this is a click and not a hover
		var CONST_TEMP_WAIT_DURATION = 1200; // 600;
		// NOTE: No popover delay with actions since it is a click event

		var g_form;

		// STRY0145237 - Directive - update to local var
		var isOverTooltip = false;
		var isClosing = false;
		// STRY0145237 - Directive - Duration code; 
		var parentMouseLeaveTimeouts = []; // added an array to collect each time mouse leave fires; need to cancel time-outs on destroy

		$scope.dtechToolTipOpen = false;
		d.enterTooltip = _enterTooltip;
		d.getImage = _getImage;
		d.init = _init;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added
		d.initTooltip = _initTooltip;
		d.leaveTooltip = _leaveTooltip;
		d.executeAction = _executeAction;
		d.parentMouseLeave = _parentMouseLeave;

		d.showActions = _showActions;

		// when the user hovers over the tooltip set overtooltip flag
		function _enterTooltip() {
			isOverTooltip = true;
		}

		function _getImage(){
			var imageName = "x_153465_discovert.EllipsesMenu24.svg";
			// only change to white if dark and using original image
			if($scope.dtechIsDark==true){
				imageName = "x_153465_discovert.ActionsMenu_White16.svg";
			} else if($scope.dtechInDataTable==true){
				imageName = "Ellipses16.svg";
			}
			return imageName;
		}

		function _executeActionWithParameters(action, params) {
			if($scope.dtechActionsObject.objectType=='task'){
				_task_executeActionWithParameters(action, params);
			} else if($scope.dtechActionsObject.objectType=='templateTask'){
				_template_executeActionWithParameters(action, params);
			}
		}

		function _template_executeActionWithParameters(action, params) {
			switch (action.action_name){
				// abstain
				case "delete_template_task":
					x_153465_discovert.DTech_Task_Actions.confirmDeleteTemplateTask(spModal, params);
					break;
				case "Activate Process Template Task":
					var activateObj = {};
					activateObj.task_sys_id = params.task_sys_id;
					dtechTemplateService.activateTemplateTask(activateObj);
					break;
				case "Deactivate Template Task":
					var deactivateObj = {};
					deactivateObj.task_sys_id = params.task_sys_id;
					dtechTemplateService.deactivateTemplateTask(deactivateObj);
					break;
				default:
					var errMsg = action.name + " - for Template Task not implemented.  Please report as an issue.";
					if(spUtil){
						spUtil.addErrorMessage(errMsg);
					} else if(g_form){
						g_form.addErrorMessage(errMsg);
					}
					break;
			}
		}

		function _task_executeActionWithParameters(action, params) {
			switch (action.action_name){
				// abstain
				case "Abstain-SendToReview":
					x_153465_discovert.DTech_Task_Actions.abstain(spModal, spUtil, g_form, params);
					break;
				// accept assignment
				case "AcceptAssignment":
					var acceptObj = {};
					acceptObj.task_sys_id = params.task_sys_id;
					dtechTaskService.acceptTask(acceptObj);
					break;
				// approve
				case "Approve-SendToReview":
					x_153465_discovert.DTech_Task_Actions.approve(spModal, spUtil, g_form, params);
					break;
				// approveSign
				case "ApproveSign-SendToReview":
					x_153465_discovert.DTech_Task_Actions.approveSign(spModal, spUtil, g_form, params);
					break;
				// task assigned
				case "assigned":
					x_153465_discovert.DTech_Task_Actions.openAssignmentModal(spModal, params.title, $scope.dtechTable, $scope.dtechTaskSysId);
					//var assignObj = {};
					//assignObj.task_sys_id = params.task_sys_id;
					//dtechTaskService.assignTask(assignObj);
					break;
				// markComplete
				case 'ClosedComplete':
					x_153465_discovert.DTech_Task_Actions.markComplete(spModal, spUtil, g_form, params);
					break;					
				// concur
				case "Concur-SendToReview":
					x_153465_discovert.DTech_Task_Actions.concur(spModal, spUtil, g_form, params);
					break;
				// concurSign
				case "ConcurSign-SendToReview":
					x_153465_discovert.DTech_Task_Actions.concurSign(spModal, spUtil, g_form, params);
					break;
				// confirmDeleteTask
				case "delete_tasks":
					x_153465_discovert.DTech_Task_Actions.confirmDeleteTask(spModal, params);
					break;
				// sendToReview
				case 'inReview':
					x_153465_discovert.DTech_Task_Actions.sendToReview(spModal, spUtil, g_form, params);
					break;
				// nonconcur
				case "NonConcur-SendToReview":
					x_153465_discovert.DTech_Task_Actions.nonconcur(spModal, spUtil, g_form, params);
					break;
				// nonconcurSign
				case "NonconcurSign-SendToReview":
					x_153465_discovert.DTech_Task_Actions.nonconcurSign(spModal, spUtil, g_form, params);
					break;
				// requestClarification
				case 'openModalRequestClarificationSP':
					x_153465_discovert.DTech_Task_Actions.requestClarification(spModal, spUtil, g_form, params);
					break;
				// requestExtension
				case 'openModalRequestExtensionSP':
					x_153465_discovert.DTech_Task_Actions.requestExtension(spModal, spUtil, g_form, params);
					break;
				// requestReassignment
				case 'openModalRequestReassignmentSP':
					x_153465_discovert.DTech_Task_Actions.requestReassignment(spModal, spUtil, g_form, params);
					break;
				// respondToClarificationRequest
				case 'openModalRespondClarificationSP':
					x_153465_discovert.DTech_Task_Actions.respondToClarificationRequest(spModal, spUtil, g_form, params);
					break;
				// respondToExtensionRequest
				case 'openModalRespondExtensionSP':
					x_153465_discovert.DTech_Task_Actions.respondToExtensionRequest(spModal, spUtil, g_form, params);
					break;
				// respondToReassignmentRequest
				case 'openModalRespondReassignmentSP':
					x_153465_discovert.DTech_Task_Actions.respondToReassignmentRequest(spModal, spUtil, g_form, params);
					break;
				// confirmPublishDraftTasks
				case "publish_tasks":
					// NOTE: this will only return true if the publish task api should be called
					var callPublishTask = x_153465_discovert.DTech_Task_Actions.confirmPublishDraftTasks(spModal, spUtil, g_form, params);
					if(callPublishTask){
						var publishObj = {};
						publishObj.task_sys_id = params.task_sys_id;
						dtechTaskService.publishTask(publishObj);
					}
					break;
				// rejectAssignment
				case 'rejectAssignment':
					x_153465_discovert.DTech_Task_Actions.rejectAssignment(spModal, spUtil, g_form, params);
					break;
				// rejectOUAssignment
				case 'rejectOUAssignment':
					x_153465_discovert.DTech_Task_Actions.rejectOUAssignment(spModal, spUtil, g_form, params);
					break;
				// rejectTask
				case "Reject-Approval":
					x_153465_discovert.DTech_Task_Actions.rejectTask(spModal, spUtil, g_form, params);
					break;
				// confirmReopenTasks
				case "Reopen":
					x_153465_discovert.DTech_Task_Actions.confirmReopenTasks(spModal, spUtil, g_form, params);
					break;
				// sendToRework
				case 'rework':
					x_153465_discovert.DTech_Task_Actions.sendToRework(spModal, spUtil, g_form, params);
					break;
				case "workInProgress":
					var startTaskhObj = {};
					startTaskhObj.task_sys_id = params.task_sys_id;
					dtechTaskService.startTask(startTaskhObj);
					break;
				default:
					var errMsg = action.name + " - for Task not implemented.  Please report as an issue.";
					if(spUtil){
						spUtil.addErrorMessage(errMsg);
					} else if(g_form){
						g_form.addErrorMessage(errMsg);
					}
					break;
			}
		}

		// executeAction()
		// this function is called from Template html
		// it is called when a user clicks on the open link
		function _executeAction(event, action) {
			if($scope.dtechActionsObject.objectType=='task'){
				dtechTaskService.getUIActionParametersByActionName($scope.dtechTaskSysId, action.action_name).then(
					function(response){
						var params = response.actionParameters;
						_executeActionWithParameters(action, params);
					});
			} else if($scope.dtechActionsObject.objectType=='templateTask'){
				dtechTemplateService.getUIActionParametersByActionName($scope.dtechTaskSysId, action.action_name).then(
					function(response){
						var params = response.actionParameters;
						_executeActionWithParameters(action, params);
					});
			}
			event.stopPropagation();
		}

		// init()
		// initialize the control, called from the Link function
		// gets a reference to the element
		function _init(rawAttrs) {
			// Set a default value when attribute not in hosting HTML
			if (angular.isUndefined(rawAttrs.dtechPopoverPlacement)) {
				$scope.dtechPopoverPlacement = "bottom";
			}

			if (angular.isUndefined(rawAttrs.dtechInDataTable)) {
				$scope.dtechInDataTable = false;
			}

			$scope.dtechToolTipOpen = 
				angular.isDefined($attrs.dtechToolTipOpen) ?
				$scope.$parent.$eval($attrs.dtechToolTipOpen) : false;

		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _initTooltip() {
			// if the user moved off of the parent before the tooltip opened, cancel the open
			if (isClosing == true) {
				_leaveTooltip();
				isClosing = false;
			}
		}

		function _leaveTooltip() {
			isOverTooltip = false;
			$scope.dtechToolTipOpen = false;

			// STRY0139742 - Increase delaying when hover directives open; set true
			isClosing = true;
		}

		function _parentMouseLeave() {
			// STRY0145237 - Directive - Duration code changes to match design; 
			// we need to track each time the below fires so we cancel on destroy
			parentMouseLeaveTimeouts.push($timeout(function() {
				if(!isOverTooltip){
					d.leaveTooltip();
				}
			}, CONST_TEMP_WAIT_DURATION));
		}

		function _showActions(event) {
			$scope.dtechToolTipOpen = true;

			// STRY0139742 - Increase delaying when hover directives open; set false
			isClosing = false;

			var actionsObject = {};
			actionsObject.taskId = $scope.dtechTaskSysId;
			$scope.dtechActionsObject = actionsObject;
			$scope.loadActions($scope.dtechTaskSysId);
		}

		// STRY0145237 - Directive - Duration code changes to match design; added
		$scope.$on("$destroy", function (event) {
			// we tracked each time mouse leave fired, now we can cancel each time-out and remove from the array
			angular.forEach(parentMouseLeaveTimeouts, function(item) {
				$timeout.cancel(item);
				parentMouseLeaveTimeouts.splice(parentMouseLeaveTimeouts.indexOf(item), 1);
			});
		});

	} // end function actionsCtrl
	// Link function links local methods to parent controller methods
	// see the list of events being monitored
	function link(scope, element, attrs, directiveCtrl) {
		// initialize the control
		// 2.8.5 | 2023-11-07 | mmcc | STRY0145237 - Directive - Duration code changes to match design; 
		// updated to pass attrs
		directiveCtrl.init(attrs);

		scope.$on('$destroy',_destroy);
		// get the location of the element hovering over
		function _destroy() {
			element.remove();
		}
	}

}
